import React from "react"
import { Link } from "gatsby"

const Layout = ({ children }) => {
  return (
    <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column" }}>
      <header style={headerStyle}>
        <div style={{ maxWidth: 1200, margin: "0 auto", display: "flex", justifyContent: "space-between", alignItems: "center", padding: "0 1rem" }}>
          <Link to="/" style={logoStyle}>
            <span style={{ fontSize: "1.4rem" }}>📦</span> DevBundles
          </Link>
          <nav style={{ display: "flex", gap: "1.5rem" }}>
            <Link to="/" style={navLinkStyle}>Bundles</Link>
            <Link to="/deals/" style={navLinkStyle}>All Deals</Link>
            <Link to="/categories/" style={navLinkStyle}>Categories</Link>
          </nav>
        </div>
      </header>
      <main style={{ flex: 1, maxWidth: 1200, margin: "0 auto", padding: "2rem 1rem", width: "100%", boxSizing: "border-box" }}>
        {children}
      </main>
      <footer style={footerStyle}>
        <p>Pricing verified on {new Date().toISOString().slice(0,10)} · No affiliate links · Solo dev focused</p>
      </footer>
    </div>
  )
}

const headerStyle = {
  background: "#0a0a0a",
  borderBottom: "1px solid #222",
  padding: "1rem 0",
  position: "sticky",
  top: 0,
  zIndex: 100,
}

const logoStyle = {
  color: "#e0e0e0",
  textDecoration: "none",
  fontWeight: 700,
  fontSize: "1.1rem",
  display: "flex",
  alignItems: "center",
  gap: "0.4rem",
}

const navLinkStyle = {
  color: "#999",
  textDecoration: "none",
  fontSize: "0.9rem",
  fontWeight: 500,
}

const footerStyle = {
  borderTop: "1px solid #222",
  padding: "2rem 1rem",
  textAlign: "center",
  color: "#666",
  fontSize: "0.8rem",
}

export default Layout
